let queries = [];

for (const item of $input.all()) {
  const user = item.json;
  const interests = user.interestedItems || [];
  const locations = user.interestedLocations || [];

  for (const product of interests) {
    for (const location of locations) {
      queries.push({
        json: {
          query: `${product} for sale in ${location}`,
          product,
          location,
          user: {
            fullName: user.fullName,
            email: user.email,
            userType: user.userType,
            plan: user.plan
          }
        }
      });
    }
  }
}

return queries;

const userContext = $("Extract-Interested-Items").first().json.user;

const groups = {};

for (const item of $input.all()) {
  const json = item.json || {};
  const email = userContext.email;

  if (!groups[email]) {
    groups[email] = {
      userEmail: email,
      results: []
    };
  }

  const organic = item.json.organic_results || [];
  groups[email].results.push(...organic.map(r => ({ ...r, category: item.json.product })));
}

return Object.values(groups).map(g => ({ json: g }));

let items = [];
for (const item of $input.all()) {
  const { results, userEmail } = item.json;
  results.slice(0, 5).forEach((result) => {
    items.push({ json: { userEmail, link: result.link, category: result.category } });
  });
}
return items;

