function extractCleanBody(html) {
  if (!html) return "";

  // Extract <body>
  const bodyMatch = html.match(/<body[^>]*>([\s\S]*?)<\/body>/i);
  let body = bodyMatch ? bodyMatch[1] : html;

  // Remove heavy/unnecessary elements
  body = body.replace(/<script[\s\S]*?<\/script>/gi, "");
  body = body.replace(/<style[\s\S]*?<\/style>/gi, "");
  body = body.replace(/<noscript[\s\S]*?<\/noscript>/gi, "");
  body = body.replace(/<svg[\s\S]*?<\/svg>/gi, "");
  body = body.replace(/<iframe[\s\S]*?<\/iframe>/gi, "");

  // Remove comments
  body = body.replace(/<!--[\s\S]*?-->/g, "");

  // Collapse whitespace
  body = body.replace(/\s+/g, " ").trim();

  // Hard limit to reduce tokens
  const MAX_CHARS = 108000;
  if (body.length > MAX_CHARS) {
    body = body.slice(0, MAX_CHARS);
  }

  return body;
}

// Usage
const html = $json.content;
const bodyContent = extractCleanBody(html);

return [
  {
    json: {
      bodyContent
    }
  }
];

// Aggregate verification results across all items
let allPassed = true;
const verificationResults = [];

for (const item of $input.all()) {
  let result = {
    isPassed: false,
    output: null,
    error: null
  };

  try {
    result.output = JSON.parse(item.json.output);
    result.originalOutput=item.json.output
    result.isPassed = true;
  } catch (e) {
    result.isPassed = false;
    result.error = e.message;
    result.output = item.json.output;
    allPassed = false;
  }

  verificationResults.push(result);
}

return [{
  json: {
    isPassed: allPassed,
    totalItems: verificationResults.length,
    passedCount: verificationResults.filter(r => r.isPassed).length,
    failedCount: verificationResults.filter(r => !r.isPassed).length,
    details: verificationResults
  }
}];
